import React from 'react';
import { Scissors, Drill as Comb, Zap as Machine } from 'lucide-react'; 

const BarberBackground = () => {
  // Criamos um array de 15 ícones para espalhar pela tela
  const icons = Array.from({ length: 15 });

  const getIcon = (index) => {
    const props = { size: 32, className: "falling-icon" };
    if (index % 3 === 0) return <Scissors {...props} />;
    if (index % 3 === 1) return <Comb {...props} />;
    return <Machine {...props} />;
  };

  return (
    <div className="barber-icon-container">
      {icons.map((_, i) => (
        <div
          key={i}
          style={{
            left: `${Math.random() * 100}%`,
            animationDuration: `${6 + Math.random() * 10}s`, // Velocidades diferentes
            animationDelay: `${Math.random() * 10}s`,       // Inícios diferentes
          }}
        >
          {getIcon(i)}
        </div>
      ))}
    </div>
  );
};

export default BarberBackground;
